sql:
SELECT AVG(salary) AS average_salary
FROM individuals
WHERE sex = 'Male' AND workclass = 'Self-emp-not-inc';

SELECT COUNT(individual_id) AS private_workers_count
FROM individuals
WHERE workclass = 'Private';

SELECT COUNT(individual_id) AS total_individuals
FROM individuals
WHERE age > 30;

SELECT COUNT(*) AS individual_count
FROM individuals
WHERE education = 'Bachelors';

SELECT AVG(age) AS average_age
FROM individuals
WHERE workclass = 'State-gov' AND salary = '>50K';

SELECT COUNT(individual_id) AS count_of_individuals_with_bachelors
FROM individuals
WHERE education = 'Bachelors';

SELECT DISTINCT i.individual_id
FROM individuals i
WHERE i.age BETWEEN 30 AND 40 AND i.salary = '>50K';

SELECT COUNT(*) 
FROM individuals 
WHERE age > 50 AND sex = '0' AND salary = '>50K';

external_knowledge:
- "sailing in the affluent waters" is a metaphor for earning a high salary;
- "the golden threshold of 50,000" refers to the condition where the average salary is above 50,000;
- Affluent waters and golden threshold are used to metaphorically describe individuals with a high average salary.

sql:
SELECT AVG(age) AS average_age
FROM individuals i
JOIN access_logs a ON i.individual_id = a.individual_id;

SELECT COUNT(*) AS number_of_individuals
FROM individuals
WHERE salary = '>50K';

SELECT workclass, COUNT(*) AS individual_count
FROM individuals
GROUP BY workclass;
